const fs = require('fs');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }
const entities = ctx.entities || {}, founder = ctx.founder || {}, tech = ctx.technology || {}, dates = ctx.key_dates || {}, revenue = ctx.revenue_targets || {};
const eafProfile = `ORGANIZATION: ${entities.EAF?.name || 'KAI-Netics Equity & Autonomy Foundry'}
EIN: ${entities.EAF?.ein || '41-4820296'}
TYPE: ${entities.EAF?.type || 'Maryland Nonstock Corp 501c3 pending'}
STATUS: ${entities.EAF?.status}
ROLE: ${entities.EAF?.role}
FOUNDER: ${founder.name} — ${(founder.credentials||[]).join(', ')}
PROGRAMS: CAKO (${tech.CAKO?.description}) | MONK (${tech.MONK?.description}) | Talent Pipeline Agreement
SERVICE AREA: Maryland, DC Metro, Northern Virginia
REVENUE IMPACT: Y1 ${revenue.year1_total} Y2 ${revenue.year2_total} Y3 ${revenue.year3_total}
KEY DATES: MEIA ${dates.meia_capstone} | CAKO Cohort 1 ${dates.cako_cohort1_launch}
COMPLIANCE: NO funds flow FP to EAF. Talent Pipeline Agreement is only structural link.`;
const dirPath = '/data/Maryland_Grants/';
let grantFiles = [];
try { grantFiles = fs.readdirSync(dirPath).filter(f => f.endsWith('.txt') || f.endsWith('.pdf') || f.endsWith('.md')); } catch(e) { grantFiles = []; }
if (grantFiles.length === 0) return [{ json: { fileName: 'No grant files', content: 'No files in /data/Maryland_Grants/', eafProfile, noFiles: true } }];
return grantFiles.map(file => {
  let content = '';
  try { content = fs.readFileSync(dirPath + file, 'utf8'); } catch(e) { content = 'Could not read: ' + e.message; }
  return { json: { fileName: file, content, eafProfile, noFiles: false } };
});

const { fileName, content, eafProfile } = $input.first().json;
const systemMessage = `You are Jordan, Grant Writer for KAI-Netics EAF. Expert in Maryland workforce development grants, federal SBIR, nonprofit funding. Analyze grants and draft winning applications. Concise, professional, outcome-focused.`;
const userMessage = `GRANT: ${fileName}
CONTENT:
${content}
EAF PROFILE:
${eafProfile}

Analyze:
1. FUNDER
2. DEADLINE
3. AWARD RANGE
4. ELIGIBILITY (flag risks)
5. FIT SCORE 0-100% with rationale
6. TOP 3 ALIGNMENT POINTS
7. TOP 2 RISKS
8. RECOMMENDED ACTION: Apply/Pass/Watch

If fit 60%+, also draft:
9. LETTER OF INTENT (250-350 words)`;
return [{ json: { systemMessage, userMessage, fileName } }];

const https = require('https');
const { systemMessage, userMessage, fileName } = $input.first().json;
const requestBody = JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, system: systemMessage, messages: [{ role: 'user', content: userMessage }] });
const options = { hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': 'REPLACE_WITH_KEY', 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(requestBody) } };
const result = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
  req.on('error', reject); req.write(requestBody); req.end();
});
let aiOutput = '';
try { aiOutput = JSON.parse(result.body).content?.[0]?.text || 'No response.'; } catch(e) { aiOutput = result.body.substring(0,500); }
return [{ json: { aiOutput, fileName, status: result.status } }];

const fs = require('fs');
const { aiOutput, fileName } = $input.first().json;
const timestamp = new Date().toISOString();
const outputPath = `/data/Aidan_Outputs/Jordan/Grant_Report_${timestamp.replace(/[:.]/g,'-')}_${fileName.replace(/[^a-z0-9]/gi,'_')}.txt`;
fs.mkdirSync('/data/Aidan_Outputs/Jordan', { recursive: true });
fs.writeFileSync(outputPath, `JORDAN GRANT REPORT — EAF\nFile: ${fileName}\nGenerated: ${timestamp}\n\n${aiOutput}`, 'utf8');
const fitMatch = aiOutput.match(/FIT SCORE[*:\s]+(\d+)[/%]/i);
const fitScore = fitMatch ? fitMatch[1] + '%' : 'See report';
const funderMatch = aiOutput.match(/FUNDER[*:\s|]+([^\n|]+)/i);
const funder = funderMatch ? funderMatch[1].trim().replace(/\*/g,'').substring(0,40) : 'See report';
const actionMatch = aiOutput.match(/RECOMMENDED ACTION[*:\s|]+([^\n|]+)/i);
const action = actionMatch ? actionMatch[1].trim().replace(/\*/g,'') : 'Review report';
const summary = `JORDAN GRANT ANALYSIS COMPLETE\nFile: ${fileName}\nFunder: ${funder}\nFit: ${fitScore}\nAction: ${action}\nSaved: /data/Aidan_Outputs/Jordan/`;
return [{ json: { summary, outputPath, fileName, fitScore, timestamp } }];

